import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.CATMZqNR.js";const b=JSON.parse('{"title":"Type Alias: WeightHealth","description":"","frontmatter":{},"headers":[],"relativePath":"api/type-aliases/WeightHealth.md","filePath":"api/type-aliases/WeightHealth.md"}'),n={name:"api/type-aliases/WeightHealth.md"};function i(s,e,l,c,h,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../README.html"><strong>monad.ai</strong></a></p><hr><p><a href="./../README.html">monad.ai</a> / WeightHealth</p><h1 id="type-alias-weighthealth" tabindex="-1">Type Alias: WeightHealth <a class="header-anchor" href="#type-alias-weighthealth" aria-label="Permalink to &quot;Type Alias: WeightHealth&quot;">​</a></h1><blockquote><p><strong>WeightHealth</strong> = <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/neurons-me/monad/blob/afb8a98bd7e97bb1630f11624b2f4c187b743f15/npm/src/kernel/adaptiveWeights.ts#L51" target="_blank" rel="noreferrer">kernel/adaptiveWeights.ts:51</a></p><p>Runtime health signals for the adaptive learning loop.</p><p>These are diagnostic, not prescriptive — they surface conditions that warrant attention, not automatic corrections. All four can be false simultaneously on a healthy, well-calibrated system.</p><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to &quot;Properties&quot;">​</a></h2><h3 id="deadscorer" tabindex="-1">deadScorer <a class="header-anchor" href="#deadscorer" aria-label="Permalink to &quot;deadScorer&quot;">​</a></h3><blockquote><p><strong>deadScorer</strong>: <code>string</code> | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/neurons-me/monad/blob/afb8a98bd7e97bb1630f11624b2f4c187b743f15/npm/src/kernel/adaptiveWeights.ts#L74" target="_blank" rel="noreferrer">kernel/adaptiveWeights.ts:74</a></p><p>Name of a scorer whose weight has dropped near the <code>WEIGHT_MIN</code> floor.</p><p>A dead scorer is effectively not participating in selection. If the scorer encodes a signal that should matter (e.g., latency for a latency-sensitive workload), the learning loop may have over-penalized it from early failures. Consider raising its per-claim <code>_weight_&lt;name&gt;</code> override to inject a floor above <code>WEIGHT_MIN</code>.</p><p><code>null</code> if no scorer is near the floor.</p><hr><h3 id="dominantscorer" tabindex="-1">dominantScorer <a class="header-anchor" href="#dominantscorer" aria-label="Permalink to &quot;dominantScorer&quot;">​</a></h3><blockquote><p><strong>dominantScorer</strong>: <code>string</code> | <code>null</code></p></blockquote><p>Defined in: <a href="https://github.com/neurons-me/monad/blob/afb8a98bd7e97bb1630f11624b2f4c187b743f15/npm/src/kernel/adaptiveWeights.ts#L62" target="_blank" rel="noreferrer">kernel/adaptiveWeights.ts:62</a></p><p>Name of a scorer that has captured more than 70% of total weight.</p><p>A dominant scorer means the other signals are largely ignored. This may be correct (e.g., resonance is genuinely the best predictor) or a sign of overfitting to a narrow workload. Inspect the scorer delta table in the offline analyzer to distinguish the two.</p><p><code>null</code> if no scorer exceeds the threshold.</p><hr><h3 id="nolearning" tabindex="-1">noLearning <a class="header-anchor" href="#nolearning" aria-label="Permalink to &quot;noLearning&quot;">​</a></h3><blockquote><p><strong>noLearning</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/neurons-me/monad/blob/afb8a98bd7e97bb1630f11624b2f4c187b743f15/npm/src/kernel/adaptiveWeights.ts#L93" target="_blank" rel="noreferrer">kernel/adaptiveWeights.ts:93</a></p><p>True when 10 or more updates have been applied but no weight has moved more than 0.002 from its default.</p><p>Possible causes: all requests are going to name-selector monads (no mesh-claim decisions), zero-contribution breakdowns (scorer values are all zero), or the bridge is not calling <code>correlateOutcome</code>. Check that <code>MONAD_DEBUG_WEIGHTS=1</code> shows updates after forwarded requests.</p><hr><h3 id="oscillation" tabindex="-1">oscillation <a class="header-anchor" href="#oscillation" aria-label="Permalink to &quot;oscillation&quot;">​</a></h3><blockquote><p><strong>oscillation</strong>: <code>boolean</code></p></blockquote><p>Defined in: <a href="https://github.com/neurons-me/monad/blob/afb8a98bd7e97bb1630f11624b2f4c187b743f15/npm/src/kernel/adaptiveWeights.ts#L83" target="_blank" rel="noreferrer">kernel/adaptiveWeights.ts:83</a></p><p>True when the recent reward signal alternates sign frequently.</p><p>Computed over the last 10 rewards: if more than 40% of consecutive pairs change sign, the learning loop is receiving contradictory signal. Common causes: two claimants with similar scores and opposite reliability profiles, or an exploration rate that is too high for the current mesh size.</p>',34)])])}const g=a(n,[["render",i]]);export{b as __pageData,g as default};
